import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { getMenus, getMenu, getImageUrl } from '../api';
import Navbar from '../components/Navbar';

/* ── Menu Detail Modal ───────────────────────────────────────────── */
function MenuDetailModal({ menuId, onClose }) {
    const [menu, setMenu] = useState(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');
    const [activeImg, setActiveImg] = useState(0);

    useEffect(() => {
        if (!menuId) return;
        setLoading(true);
        setError('');
        setActiveImg(0);
        getMenu(menuId)
            .then((res) => setMenu(res.data?.data || res.data))
            .catch(() => setError('Gagal memuat detail menu.'))
            .finally(() => setLoading(false));
    }, [menuId]);

    // Close on backdrop click
    const handleBackdrop = (e) => {
        if (e.target === e.currentTarget) onClose();
    };

    // Close on Escape
    useEffect(() => {
        const handler = (e) => { if (e.key === 'Escape') onClose(); };
        document.addEventListener('keydown', handler);
        return () => document.removeEventListener('keydown', handler);
    }, [onClose]);

    // Prevent body scroll while modal open
    useEffect(() => {
        document.body.style.overflow = 'hidden';
        return () => { document.body.style.overflow = ''; };
    }, []);

    const formatDate = (d) =>
        new Date(d).toLocaleDateString('id-ID', { day: 'numeric', month: 'long', year: 'numeric' });

    const formatPrice = (p) =>
        new Intl.NumberFormat('id-ID', { style: 'currency', currency: 'IDR', maximumFractionDigits: 0 }).format(p);

    return (
        <div className="modal-backdrop" onClick={handleBackdrop}>
            <div className="modal-box" role="dialog" aria-modal="true">
                {/* Close button */}
                <button className="modal-close" onClick={onClose} aria-label="Tutup">✕</button>

                {loading && (
                    <div className="modal-loading">
                        <div className="loading-spinner" />
                        <p>Memuat detail…</p>
                    </div>
                )}

                {error && <div className="alert alert-error" style={{ margin: '24px' }}>{error}</div>}

                {!loading && menu && (
                    <>
                        {/* Image gallery */}
                        {menu.posters && menu.posters.length > 0 && (
                            <div className="modal-gallery">
                                <img
                                    src={getImageUrl(menu.posters[activeImg])}
                                    alt={menu.name}
                                    className="modal-gallery-main"
                                    onError={(e) => { e.target.style.display = 'none'; }}
                                />
                                {menu.posters.length > 1 && (
                                    <div className="modal-gallery-thumbs">
                                        {menu.posters.map((p, i) => (
                                            <button
                                                key={i}
                                                className={`modal-thumb${activeImg === i ? ' active' : ''}`}
                                                onClick={() => setActiveImg(i)}
                                                aria-label={`Gambar ${i + 1}`}
                                            >
                                                <img
                                                    src={getImageUrl(p)}
                                                    alt={`Poster ${i + 1}`}
                                                    onError={(e) => { e.target.style.display = 'none'; }}
                                                />
                                            </button>
                                        ))}
                                    </div>
                                )}
                            </div>
                        )}

                        {/* Content */}
                        <div className="modal-content">
                            <div className="modal-header">
                                <h2 className="modal-title">{menu.name}</h2>
                                <span className="modal-badge">
                  {formatDate(menu.start_date)} – {formatDate(menu.end_date)}
                </span>
                            </div>

                            {menu.description && (
                                <p className="modal-desc">{menu.description}</p>
                            )}

                            {/* Food packages */}
                            {menu.food_packages && menu.food_packages.length > 0 && (
                                <div className="modal-packages">
                                    <h3 className="modal-section-title">Food Packages</h3>
                                    <div className="modal-pkg-grid">
                                        {menu.food_packages.map((fp) => (
                                            <div key={fp.id} className="modal-pkg-card">
                                                <div className="modal-pkg-name">{fp.name}</div>
                                                {fp.price !== undefined && fp.price !== null && (
                                                    <div className="modal-pkg-price">{formatPrice(fp.price)}</div>
                                                )}
                                                {fp.description && (
                                                    <div className="modal-pkg-desc">{fp.description}</div>
                                                )}
                                                {fp.min_persons !== undefined && fp.max_persons !== undefined && (
                                                    <div className="modal-pkg-meta">
                                                        👥 {fp.min_persons}–{fp.max_persons} orang
                                                    </div>
                                                )}
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            )}

                            <div className="modal-footer">
                                <Link to="/booking" className="btn-primary" onClick={onClose}>
                                    Pesan Sekarang
                                </Link>
                            </div>
                        </div>
                    </>
                )}
            </div>
        </div>
    );
}

/* ── Menu Card ───────────────────────────────────────────────────── */
function MenuCard({ menu, onSelect }) {
    const poster = menu.posters && menu.posters.length > 0
        ? getImageUrl(menu.posters[0])
        : null;

    const formatDate = (d) =>
        new Date(d).toLocaleDateString('id-ID', { day: 'numeric', month: 'long', year: 'numeric' });

    return (
        <div className="menu-card" onClick={() => onSelect(menu.id)} style={{ cursor: 'pointer' }}>
            <div className="menu-card-img">
                {poster ? (
                    <img src={poster} alt={menu.name} onError={(e) => { e.target.style.display = 'none'; }} />
                ) : (
                    <div className="menu-no-img">🍜</div>
                )}
                <div className="menu-card-overlay">
                    <span className="menu-card-detail-btn">Lihat Detail →</span>
                </div>
            </div>
            <div className="menu-card-body">
                <h3>{menu.name}</h3>
                <p className="menu-dates">
                    {formatDate(menu.start_date)} – {formatDate(menu.end_date)}
                </p>
                {menu.food_packages && menu.food_packages.length > 0 && (
                    <div className="menu-packages">
                        <span className="pkg-label">Packages:</span>
                        <div className="pkg-list">
                            {menu.food_packages.slice(0, 3).map((fp) => (
                                <span key={fp.id} className="pkg-tag">{fp.name}</span>
                            ))}
                            {menu.food_packages.length > 3 && (
                                <span className="pkg-tag muted">+{menu.food_packages.length - 3} more</span>
                            )}
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
}

/* ── Dashboard Page ──────────────────────────────────────────────── */
export default function DashboardPage() {
    const [menus, setMenus] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');
    const [selectedMenuId, setSelectedMenuId] = useState(null);

    useEffect(() => {
        getMenus()
            .then((res) => setMenus(res.data?.data || []))
            .catch(() => setError('Failed to load menus.'))
            .finally(() => setLoading(false));
    }, []);

    return (
        <div className="page">
            <Navbar />

            {/* Hero */}
            <section className="hero">
                <div className="hero-content">
                    <span className="hero-badge">✦ Fine Dining Experience</span>
                    <h1 className="hero-title">Welcome to<br /><em>BimaResto</em></h1>
                    <p className="hero-subtitle">
                        A culinary journey through flavors crafted with passion and the finest local ingredients.
                        Reserve your table and experience something extraordinary.
                    </p>
                    <div className="hero-cta">
                        <Link to="/booking" className="btn-primary">Book a Table</Link>
                        <a href="#menus" className="btn-outline">View Menu</a>
                    </div>
                </div>
                <div className="hero-visual">
                    <div className="hero-orb orb1" />
                    <div className="hero-orb orb2" />
                    <div className="hero-plate">🍽</div>
                </div>
            </section>

            {/* About */}
            <section className="section about-section" id="about">
                <div className="section-inner">
                    <div className="section-label">About Us</div>
                    <h2 className="section-title">The Story Behind BimaResto</h2>
                    <div className="about-grid">
                        <div className="about-card">
                            <div className="about-icon">🌿</div>
                            <h3>Fresh Ingredients</h3>
                            <p>We source our ingredients daily from local farms and trusted suppliers to guarantee the freshest dishes on your plate.</p>
                        </div>
                        <div className="about-card">
                            <div className="about-icon">👨‍🍳</div>
                            <h3>Expert Chefs</h3>
                            <p>Our culinary team brings decades of combined experience, blending traditional Indonesian flavors with modern techniques.</p>
                        </div>
                        <div className="about-card">
                            <div className="about-icon">🏛</div>
                            <h3>Warm Ambience</h3>
                            <p>Designed for comfort and intimacy, our space is perfect for family gatherings, romantic dinners, and corporate events.</p>
                        </div>
                    </div>
                </div>
            </section>

            {/* Menus */}
            <section className="section menus-section" id="menus">
                <div className="section-inner">
                    <div className="section-label">Our Menu</div>
                    <h2 className="section-title">Current Offerings</h2>

                    {loading && (
                        <div className="loading-box">
                            <div className="loading-spinner" />
                            <p>Loading menus…</p>
                        </div>
                    )}
                    {error && <div className="alert alert-error">{error}</div>}

                    {!loading && menus.length === 0 && !error && (
                        <div className="empty-state">
                            <span>🍽</span>
                            <p>No menus available at the moment. Check back soon!</p>
                        </div>
                    )}

                    <div className="menus-grid">
                        {menus.map((menu) => (
                            <MenuCard key={menu.id} menu={menu} onSelect={setSelectedMenuId} />
                        ))}
                    </div>

                    {menus.length > 0 && (
                        <div className="section-cta">
                            <Link to="/booking" className="btn-primary">Reserve Your Table</Link>
                        </div>
                    )}
                </div>
            </section>

            {/* Contact */}
            <section className="section contact-section" id="contact">
                <div className="section-inner">
                    <div className="section-label">Contact</div>
                    <h2 className="section-title">Find Us</h2>
                    <div className="contact-grid">
                        <div className="contact-item">
                            <div className="contact-icon">📍</div>
                            <div>
                                <h4>Address</h4>
                                <p>Jl. Kuliner Raya No. 12<br />Jakarta Selatan, 12430</p>
                            </div>
                        </div>
                        <div className="contact-item">
                            <div className="contact-icon">📞</div>
                            <div>
                                <h4>Phone</h4>
                                <p>+62 21 1234 5678</p>
                                <p>+62 812 3456 7890</p>
                            </div>
                        </div>
                        <div className="contact-item">
                            <div className="contact-icon">🕐</div>
                            <div>
                                <h4>Opening Hours</h4>
                                <p>Mon – Fri: 11:00 – 22:00</p>
                                <p>Sat – Sun: 10:00 – 23:00</p>
                            </div>
                        </div>
                        <div className="contact-item">
                            <div className="contact-icon">✉️</div>
                            <div>
                                <h4>Email</h4>
                                <p>info@bimaresto.id</p>
                                <p>booking@bimaresto.id</p>
                            </div>
                        </div>
                    </div>
                </div>
            </section>

            <footer className="footer">
                <p>© 2025 BimaResto. All rights reserved.</p>
            </footer>

            {/* Menu Detail Modal */}
            {selectedMenuId && (
                <MenuDetailModal
                    menuId={selectedMenuId}
                    onClose={() => setSelectedMenuId(null)}
                />
            )}
        </div>
    );
}
